mapper.select:
SELECT * FROM ( SELECT P.PRS_ID as id, P.PRS_NAME as name, P.STORED_FILE_NM as image, P.STATUS_MSG as status, P.LIST_ORDER, P.PRS_COUNTRY, IFNULL(A.viewCount, 0) as viewCount, IFNULL(P.FOLLOWER_CNT, 0) AS FOLLOWER_CNT,
-- 글로벌 랭킹 보존 ROW_NUMBER() OVER ( ORDER BY ( IFNULL(A.viewCount, 0) * 1 + IFNULL(P.LIKE_CNT, 0) * 3 + IFNULL(P.FOLLOWER_CNT, 0) * 5 ) DESC, IFNULL(A.viewCount, 0) DESC, IFNULL(P.FOLLOWER_CNT, 0) DESC, P.PRS_ID ASC ) AS GLOBAL_RANK,
(SELECT COUNT(*) FROM WH_PRESS WHERE PRS_USE_YN = 'Y' AND IS_STAR = 'Y') AS TOTAL_STARS
FROM WH_PRESS P LEFT JOIN ( SELECT PRS_ID, COUNT(*) as viewCount FROM WH_AD_LOG WHERE ACTION = 'IMPRESSION' GROUP BY PRS_ID ) A ON P.PRS_ID = A.PRS_ID WHERE P.PRS_USE_YN = 'Y' AND P.IS_STAR = 'Y' ) T -- 🌟 [핵심 로직] 글로벌 어드민(1~16번) + 로컬 어드민(17~32번 중 접속 유저의 국가만) 추출 WHERE T.LIST_ORDER BETWEEN 1 AND 16 OR ( T.LIST_ORDER BETWEEN 17 AND 32
AND T.PRS_COUNTRY = #{country}
) ORDER BY T.LIST_ORDER ASC

SELECT A.CON_ID, A.CON_BODY, A.YOUTUBE_URL, A.CREATED_DATE, A.IS_PINNED, A.PRS_ID, B.PRS_NAME, B.STORED_FILE_NM, 'STAR' AS FEED_TYPE,
-- 🌟 [수정] PPRO 조인 제거 후 A(본체) 테이블에서 직접 참조. N이면 NULL. IF(A.IS_PINNED = 'Y', A.PIN_LINK_TEXT1, NULL) AS PIN_LINK_TEXT1, IF(A.IS_PINNED = 'Y', A.PIN_LINK_URL1, NULL) AS PIN_LINK_URL1, IF(A.IS_PINNED = 'Y', A.PIN_LINK_TEXT2, NULL) AS PIN_LINK_TEXT2, IF(A.IS_PINNED = 'Y', A.PIN_LINK_URL2, NULL) AS PIN_LINK_URL2
FROM WH_STAR_CONTENT A JOIN WH_PRESS B ON A.PRS_ID = B.PRS_ID WHERE A.CON_ID = #{conId}

SELECT * FROM STAR_CONTENT_MEDIA
WHERE CON_ID = #{conId}
ORDER BY SORT_ORDER ASC

