mapper.insert:
INSERT INTO CLAIM_TOKENS (
    PAGE_ID, EMAIL, TEMP_PWD, TOKEN, EXPIRES_AT, USED
) VALUES (
    #{pageId}, #{email}, #{password}, #{token}, DATE_ADD(NOW(), INTERVAL 15 MINUTE), 0
)

mapper.update:
UPDATE WH_PRESS 
SET OWNER_EMAIL = #{email}, 
    PRS_PWD = CONCAT('*', UPPER(SHA1(UNHEX(SHA1(#{password}))))) 
WHERE PRS_ID = #{pageId};

UPDATE CLAIM_TOKENS SET USED = 1 WHERE TOKEN = #{token};

mapper.select:
SELECT PRS_ID, PRS_NAME, STORED_FILE_NM FROM ( ( SELECT P.PRS_ID, P.PRS_NAME, P.STORED_FILE_NM, 1 AS grp FROM WH_PRESS P JOIN WH_STAR_CONTENT C ON P.PRS_ID = C.PRS_ID WHERE P.PRS_USE_YN = 'Y' AND P.IS_STAR = 'Y'
AND P.PRS_ID != #{excludePageId}
GROUP BY P.PRS_ID, P.PRS_NAME, P.STORED_FILE_NM ORDER BY MAX(C.CREATED_DATE) DESC LIMIT 16 ) UNION DISTINCT ( SELECT P.PRS_ID, P.PRS_NAME, P.STORED_FILE_NM, 2 AS grp FROM WH_PRESS P WHERE P.PRS_USE_YN = 'Y' AND P.IS_STAR = 'Y'
AND P.PRS_ID != #{excludePageId}
ORDER BY RAND() LIMIT 20 ) ) AS COMBINED GROUP BY PRS_ID, PRS_NAME, STORED_FILE_NM ORDER BY MIN(grp) ASC, RAND() LIMIT 20

