mapper.select:
SELECT COUNT(*) 
FROM WH_AD_LOG 
WHERE PRS_ID = #{starId}

SELECT P.PRS_ID as id, P.PRS_NAME as name, P.STORED_FILE_NM as image, P.STATUS_MSG as status, IFNULL(P.FOLLOWER_CNT, 0) AS FOLLOWER_CNT, IFNULL(A.viewCount, 0) AS viewCount FROM WH_PRESS P -- 게시물을 조인 JOIN WH_STAR_CONTENT C ON P.PRS_ID = C.PRS_ID -- 조회수(뷰카운트) 조인 LEFT JOIN ( SELECT PRS_ID, COUNT(*) as viewCount FROM WH_AD_LOG WHERE ACTION = 'IMPRESSION' GROUP BY PRS_ID ) A ON P.PRS_ID = A.PRS_ID WHERE P.PRS_USE_YN = 'Y' AND P.IS_STAR = 'Y' -- 대표님 아이디어: 토큰이 있는 진짜 가입 유저만 AND P.PRS_TOKEN IS NOT NULL AND P.PRS_TOKEN != '' -- 필터: 접속자의 국가(선택사항, 필요없으면 제거 가능)
AND P.PRS_COUNTRY = #{country}
-- 스타 단위로 그룹화 GROUP BY P.PRS_ID, P.PRS_NAME, P.STORED_FILE_NM, P.STATUS_MSG, P.FOLLOWER_CNT, A.viewCount -- 대표님 아이디어: 컨텐츠가 딱 1개인 사람만! HAVING COUNT(C.CON_ID) = 1 LIMIT 40
